35	impl Parse for SerdeAttribute {
36	    fn parse(tokens: ParseStream) -> syn::Result<Self> {
37	        let parsed = Punctuated::<MetaNameValue, Token![,]>::parse_terminated(tokens)?;
38	        for kv in parsed {
39	            if kv.path.is_ident("rename") {
40	                if let Expr::Lit(ExprLit {
41	                    lit: Lit::Str(str), ..
42	                }) = kv.value
43	                {
44	                    return Ok(SerdeAttribute { rename: str });
45	                }
46	            }
47	        }
48	        Err(syn::Error::new(
49	            tokens.span(),
50	            "Invalid rename detected, expect #[serde(rename = \"name\")]",
51	        ))
52	    }
53	}
