55	fn parse_variants(
56	    variants: &Punctuated<Variant, Comma>,
57	) -> (Vec<&Ident>, Vec<TokenStream>, Vec<TokenStream>) {
58	    let mut name_vec = Vec::new();
59	    let mut alias_vec = Vec::new();
60	    let mut param_vec = Vec::new();
61	
62	    for var in variants {
63	        let name = &var.ident;
64	        let alias = var
65	            .attrs
66	            .iter()
67	            .find(|attr| attr.path().is_ident("serde"))
68	            .map(|attr| {
69	                attr.parse_args::<SerdeAttribute>()
70	                    .map(|x| {
71	                        x.rename
72	                            .value()
73	                            .parse::<TokenStream>()
74	                            .expect("Failed to convert LitStr to Ident TokenStream")
75	                    })
76	                    .unwrap_or_else(syn::Error::into_compile_error)
77	            })
78	            .ok_or(syn::Error::new(
79	                var.span(),
80	                "#[serde(alias = \"name\")] is missing",
81	            ))
82	            .unwrap_or_else(syn::Error::into_compile_error);
83	        let param = var
84	            .attrs
85	            .iter()
86	            .find(|attr| attr.path().is_ident("param"))
87	            .map(|attr| match &attr.meta {
88	                Meta::List(list) => list.tokens.to_string().replace('=', ":").parse(),
89	                _ => panic!("Invalid"),
90	            })
91	            .unwrap_or("".parse())
92	            .unwrap();
93	
94	        name_vec.push(name);
95	        alias_vec.push(alias);
96	        param_vec.push(param);
97	    }
98	
99	    (name_vec, alias_vec, param_vec)
100	}
