102	fn generate_declare_param(
103	    meta_param: &Ident,
104	    variant_names: &[&Ident],
105	    aliases: &Vec<TokenStream>,
106	    params: &[TokenStream],
107	) -> TokenStream {
108	    let default_param_of_variant: Vec<_> = variant_names
109	        .iter()
110	        .map(|name| format_ident!("DefaultParamOf{}", name))
111	        .collect();
112	    let params_with_default = params.iter().map(|x| {
113	        if x.to_string() != "" {
114	            quote!(#x, ..Default::default())
115	        } else {
116	            quote!(..Default::default())
117	        }
118	    });
119	    quote! {
120	        trait DefaultParam {
121	            fn param() -> #meta_param;
122	        }
123	
124	        #(
125	            // Declare struct DefaultParamOf`#variant_name`
126	            #[derive(Debug, Clone, Copy)]
127	            struct #default_param_of_variant;
128	
129	            // impl `DefaultParam` for `DefaultParamOf#variant_name`
130	            impl DefaultParam for #default_param_of_variant {
131	                fn param() -> #meta_param {
132	                    #meta_param {
133	                        #params_with_default
134	                    }
135	                }
136	            }
137	        )*
138	
139	        // An internal helper struct for parsing the RuntimeParam
140	        #[derive(Deserialize, Debug, Clone, Copy)]
141	        #[serde(deny_unknown_fields)]
142	        struct AbstractRuntimeParam {
143	            #(
144	                #[serde(default)]
145	                #aliases: RuntimeParamHelper<#default_param_of_variant>,
146	            )*
147	        }
148	
149	        // AbstractRuntimeParam => GlobalRuntimeParam, extract fields from AbstractRuntimeParam
150	        impl From<AbstractRuntimeParam> for GlobalRuntimeParam {
151	            fn from(value: AbstractRuntimeParam) -> Self {
152	                Self {
153	                    #(
154	                        #aliases: value.#aliases.into(),
155	                    )*
156	                }
157	            }
158	        }
159	
160	        /// A global runtime parameter for zenoh runtimes
161	        // pub is needed within lazy_static
162	        pub struct GlobalRuntimeParam {
163	            #(
164	                #aliases: #meta_param,
165	            )*
166	        }
167	
168	    }
169	}
