171	pub(crate) fn derive_register_param(input: DeriveInput) -> Result<TokenStream, syn::Error> {
172	    // enum representing the runtime
173	    let enum_name = &input.ident;
174	
175	    // Parse the parameter to register, called meta_param
176	    let attr = input
177	        .attrs
178	        .iter()
179	        .find(|attr| attr.path().is_ident("param"))
180	        .ok_or(syn::Error::new(
181	            input.span(),
182	            "Expected attribute #[param(StructName)] is missing.",
183	        ))?;
184	    let meta_param = match &attr.meta {
185	        Meta::List(list) => syn::parse2::<Ident>(list.tokens.to_token_stream()),
186	        _ => Err(syn::Error::new(
187	            attr.span(),
188	            format!("Failed to parse #[param({})]", attr.to_token_stream()),
189	        )),
190	    }?;
191	
192	    // Parse the variants and associated parameters of the enum
193	    let variants = match input.data {
194	        Data::Enum(DataEnum { variants, .. }) => variants,
195	        _ => unimplemented!("Only enum is supported."),
196	    };
197	    let (variant_names, aliases, params) = parse_variants(&variants);
198	    let declare_param_quote =
199	        generate_declare_param(&meta_param, &variant_names, &aliases, &params);
200	
201	    let tokens = quote! {
202	
203	        use ron::{extensions::Extensions, options::Options};
204	        use #enum_name::*;
205	
206	        lazy_static! {
207	            // We need to hold the reference of ZENOH_RUNTIME_ENV_STRING to prevent the issue of
208	            // "returning a value referencing data owned by the current function"
209	            pub static ref ZENOH_RUNTIME_ENV_STRING: String = env::var(ZENOH_RUNTIME_ENV).unwrap_or("()".to_string());
210	            pub static ref ZRUNTIME_PARAM: GlobalRuntimeParam = Options::default()
211	                .with_default_extension(Extensions::IMPLICIT_SOME)
212	                .from_str::<AbstractRuntimeParam>(&ZENOH_RUNTIME_ENV_STRING)
213	                .unwrap()
214	                .into();
215	        }
216	
217	        #declare_param_quote
218	
219	        impl #enum_name {
220	            #[doc = concat!("Create an iterator from ", stringify!(#enum_name))]
221	            pub fn iter() -> impl Iterator<Item = #enum_name> {
222	                [#(#variant_names,)*].into_iter()
223	            }
224	
225	            #[doc = "Initialize the tokio runtime according to the given config"]
226	            fn init(&self) -> Result<Runtime> {
227	                match self {
228	                    #(
229	                        #variant_names => {
230	                            ZRUNTIME_PARAM.#aliases.build(#variant_names)
231	                        },
232	                    )*
233	                }
234	            }
235	
236	        }
237	
238	        #[doc = concat!(
239	            "Borrow the underlying `",
240	            stringify!(#meta_param),
241	            "` from ",
242	            stringify!(#enum_name)
243	        )]
244	        impl Borrow<#meta_param> for #enum_name {
245	            fn borrow(&self) -> &#meta_param {
246	                match self {
247	                    #(
